mapper.select:
SELECT ,

FROM ENTITIES ENT
    LEFT OUTER JOIN SCENARIOS SCNR ON SCNR.SCENARIO_ID = ENT.SCENARIO_ID
WHERE ENT.ACTIVATED_AT <= #{currentDate, jdbcType=TIMESTAMP}
    AND ENT.STATE_ID = #{stateId, jdbcType=INTEGER}
    AND ENT.CREATED_AT >= date '${searchSet.partitionLowerBoundaryDate}'
    AND ENT.CREATED_AT < date '${searchSet.partitionUpperBoundaryDate}'
ORDER BY ENT.ACTIVATED_AT, ENT.CREATED_AT
LIMIT #{maxCount, jdbcType=INTEGER}

mapper.update:
UPDATE ENTITIES
SET ACTIVATED_AT = #{entity.activatedAt, jdbcType=TIMESTAMP}
WHERE ENTITY_ID = #{searchSet.entityId, jdbcType=VARCHAR}
  AND CREATED_AT >= date '${searchSet.partitionLowerBoundaryDate}'
  AND CREATED_AT < date '${searchSet.partitionUpperBoundaryDate}'
